122→    private boolean displayNameUpdateWasNeeded(ReaderTagList serverTopics) {
123→        boolean updateDone = false;
124→
125→        for (ReaderTag tag : serverTopics) {
126→            String tagNameBefore = tag.getTagDisplayName();
127→            if (tag.isFollowedSites()) {
128→                tag.setTagDisplayName(mContext.getString(R.string.reader_following_display_name));
129→                if (!tagNameBefore.equals(tag.getTagDisplayName())) updateDone = true;
130→            } else if (tag.isDiscover()) {
131→                tag.setTagDisplayName(mContext.getString(R.string.reader_discover_display_name));
132→                if (!tagNameBefore.equals(tag.getTagDisplayName())) updateDone = true;
133→            } else if (tag.isPostsILike()) {
134→                tag.setTagDisplayName(mContext.getString(R.string.reader_my_likes_display_name));
135→                if (!tagNameBefore.equals(tag.getTagDisplayName())) updateDone = true;
136→            }
137→        }
138→
139→        return updateDone;
140→    }
