318→    private void handleFollowedBlogsResponse(final JSONObject jsonObject) {
319→        new Thread() {
320→            @Override
321→            public void run() {
322→                ReaderBlogList serverBlogs = ReaderBlogList.fromJson(jsonObject);
323→                ReaderBlogList localBlogs = ReaderBlogTable.getFollowedBlogs();
324→
325→                if (!localBlogs.isSameList(serverBlogs)) {
326→                    // always update the list of followed blogs if there are *any* changes between
327→                    // server and local (including subscription count, description, etc.)
328→                    ReaderBlogTable.setFollowedBlogs(serverBlogs);
329→                    // ...but only update the follow status and alert that followed blogs have
330→                    // changed if the server list doesn't have the same blogs as the local list
331→                    // (ie: a blog has been followed/unfollowed since local was last updated)
332→                    if (!localBlogs.hasSameBlogs(serverBlogs)) {
333→                        ReaderPostTable.updateFollowedStatus();
334→                        AppLog.i(AppLog.T.READER, "reader blogs service > followed blogs changed");
335→                        EventBus.getDefault().post(new ReaderEvents.FollowedBlogsChanged());
336→                    }
337→                }
338→
339→                taskCompleted(UpdateTask.FOLLOWED_BLOGS);
340→            }
341→        }.start();
342→    }
