263→    /*
264→     * assigns author-related info to the passed post from the passed JSON "author" object
265→     */
266→    private static void assignAuthorFromJson(ReaderPost post, JSONObject jsonAuthor) {
267→        if (jsonAuthor == null) {
268→            return;
269→        }
270→
271→        post.mAuthorName = JSONUtils.getStringDecoded(jsonAuthor, "name");
272→        post.mAuthorFirstName = JSONUtils.getStringDecoded(jsonAuthor, "first_name");
273→        post.authorId = jsonAuthor.optLong("ID");
274→        post.authorBlogId = jsonAuthor.optLong("site_ID");
275→
276→        // v1.2 endpoint contains a "has_avatar" boolean which tells us whether the author
277→        // has a valid avatar - if this field exists and is set to false, skip setting
278→        // the avatar URL
279→        boolean hasAvatar;
280→        if (jsonAuthor.has("has_avatar")) {
281→            hasAvatar = jsonAuthor.optBoolean("has_avatar");
282→        } else {
283→            hasAvatar = true;
284→        }
285→        if (hasAvatar) {
286→            post.mPostAvatar = JSONUtils.getString(jsonAuthor, "avatar_URL");
287→        }
288→
289→        // site_URL doesn't exist for /sites/ endpoints, so get it from the author
290→        if (TextUtils.isEmpty(post.mBlogUrl)) {
291→            post.setBlogUrl(JSONUtils.getString(jsonAuthor, "URL"));
292→        }
293→
294→        post.setAuthorBlogUrl(JSONUtils.getString(jsonAuthor, "URL"));
295→    }
