297→    /*
298→     * assigns primary/secondary tags to the passed post from the passed JSON "tags" object
299→     */
300→    private static void assignTagsFromJson(ReaderPost post, JSONObject jsonTags) {
301→        if (jsonTags == null) {
302→            return;
303→        }
304→
305→        Iterator<String> it = jsonTags.keys();
306→        if (!it.hasNext()) {
307→            return;
308→        }
309→
310→        // most popular tag & second most popular tag, based on usage count on this blog
311→        String mostPopularTag = null;
312→        String nextMostPopularTag = null;
313→        int popularCount = 0;
314→
315→        ReaderTagList tags = new ReaderTagList();
316→        while (it.hasNext()) {
317→            JSONObject jsonThisTag = jsonTags.optJSONObject(it.next());
318→            String thisTagName = UrlUtils.urlDecode(JSONUtils.getString(jsonThisTag, "slug"));
319→
320→            ReaderTag tag = ReaderUtils.getTagFromTagName(thisTagName, ReaderTagType.DEFAULT);
321→            tags.add(tag);
322→
323→            // if the number of posts on this blog that use this tag is higher than previous,
324→            // set this as the most popular tag, and set the second most popular tag to
325→            // the current most popular tag
326→            int postCount = jsonThisTag.optInt("post_count");
327→            if (postCount > popularCount) {
328→                nextMostPopularTag = mostPopularTag;
329→                mostPopularTag = thisTagName;
330→                popularCount = postCount;
331→            } else if (nextMostPopularTag == null) {
332→                nextMostPopularTag = thisTagName;
333→            }
334→        }
335→
336→        // don't set primary tag if one is already set
337→        if (!post.hasPrimaryTag()) {
338→            post.setPrimaryTag(mostPopularTag);
339→        }
340→        post.setSecondaryTag(nextMostPopularTag);
341→        post.setTags(tags);
342→    }
