344→    /*
345→     * extracts a title from a post's excerpt - used when the post has no title
346→     */
347→    private static String extractTitle(final String excerpt, int maxLen) {
348→        if (TextUtils.isEmpty(excerpt)) {
349→            return null;
350→        }
351→
352→        if (excerpt.length() < maxLen) {
353→            return excerpt.trim();
354→        }
355→
356→        StringBuilder result = new StringBuilder();
357→        BreakIterator wordIterator = BreakIterator.getWordInstance();
358→        wordIterator.setText(excerpt);
359→        int start = wordIterator.first();
360→        int end = wordIterator.next();
361→        int totalLen = 0;
362→        while (end != BreakIterator.DONE) {
363→            String word = excerpt.substring(start, end);
364→            result.append(word);
365→            totalLen += word.length();
366→            if (totalLen >= maxLen) {
367→                break;
368→            }
369→            start = end;
370→            end = wordIterator.next();
371→        }
372→
373→        if (totalLen == 0) {
374→            return null;
375→        }
376→        return result.toString().trim() + "...";
377→    }
