 89→    private static void doScheduleJobWithBundle(Context context, PersistableBundle extras, int jobId) {
 90→        // schedule the JobService here for API >= 26. The JobScheduler is available since API 21, but
 91→        // it's preferable to use it only since enforcement in API 26 to not break any old behavior
 92→        ComponentName componentName = new ComponentName(context, ReaderPostJobService.class);
 93→
 94→        JobInfo jobInfo = new JobInfo.Builder(jobId, componentName)
 95→                .setRequiresCharging(false)
 96→                .setRequiredNetworkType(JobInfo.NETWORK_TYPE_ANY)
 97→                .setOverrideDeadline(0) // if possible, try to run right away
 98→                .setExtras(extras)
 99→                .build();
100→
101→        JobScheduler jobScheduler = (JobScheduler) context.getSystemService(Context.JOB_SCHEDULER_SERVICE);
102→        int resultCode = jobScheduler.schedule(jobInfo);
103→        if (resultCode == JobScheduler.RESULT_SUCCESS) {
104→            AppLog.i(AppLog.T.READER, "reader post service > job scheduled");
105→        } else {
106→            AppLog.e(AppLog.T.READER, "reader post service > job could not be scheduled");
107→        }
108→    }
