 69→        ReaderActions.UpdateResultListener listener = new ReaderActions.UpdateResultListener() {
 70→            @Override
 71→            public void onUpdateResult(ReaderActions.UpdateResult result) {
 72→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsEnded(result, action));
 73→                mCompletionListener.onCompleted(mListenerCompanion);
 74→            }
 75→        };
