import org.wordpress.android.ui.reader.utils.ReaderUtilsWrapper
import javax.inject.Inject

class BloggingPromptsPostTagProvider @Inject constructor(
    private val readerUtilsWrapper: ReaderUtilsWrapper,
) {
    fun promptIdTag(
        tagUrl: String
    ): String = readerUtilsWrapper.getTagFromTagUrl(tagUrl)
        .takeIf { it.isNotBlank() }
        ?: BLOGGING_PROMPT_TAG

    fun promptIdSearchReaderTag(
        tagUrl: String
    ): ReaderTag {
        val tag = readerUtilsWrapper.getTagFromTagName(
            promptIdTag(tagUrl),
            ReaderTagType.FOLLOWED,
        )

        // If the prompt tag isn't followed, it won't exist in the Reader tag DB and the returned [ReaderTag]
        // won't have an endpoint. Without an endpoint, the tag isn't treated as a "tag topic" which changes
        // sorting/pagination (uses date_published instead of date_tagged) and breaks infinite scroll.
        if (tag.endpoint.isBlank()) {
            tag.endpoint = ReaderPostLogic.formatFullEndpointForTag(tag.tagSlug)
        }

        return tag
    }

    companion object {
        const val BLOGGING_PROMPT_TAG = "dailyprompt"
        const val BLOGANUARY_TAG = "bloganuary"
    }
}"}

