142→    private void handleUpdateTagsResponse(final JSONObject jsonObject) {
143→        new Thread() {
144→            @Override
145→            public void run() {
146→                // get server topics, both default & followed - but use "recommended" for logged-out
147→                // reader since user won't have any followed tags
148→                ReaderTagList serverTopics = new ReaderTagList();
149→                serverTopics.addAll(parseTags(jsonObject, "default", ReaderTagType.DEFAULT));
150→
151→                boolean displayNameUpdateWasNeeded = displayNameUpdateWasNeeded(serverTopics);
152→
153→                serverTopics.addAll(parseTags(jsonObject, "subscribed", ReaderTagType.FOLLOWED));
154→
155→                // manually insert Bookmark tag, as server doesn't support bookmarking yet
156→                // and check if we are going to change it to trigger UI update in case of downgrade
157→                serverTopics.add(
158→                        new ReaderTag(
159→                                "",
160→                                mContext.getString(R.string.reader_save_for_later_display_name),
161→                                mContext.getString(R.string.reader_save_for_later_title),
162→                                "",
163→                                ReaderTagType.BOOKMARKED
164→                        )
165→                );
166→
167→                // manually insert DISCOVER_POST_CARDS tag which is used to store posts for the discover tab
168→                serverTopics.add(ReaderTag.createDiscoverPostCardsTag());
169→
170→                // parse topics from the response, detect whether they're different from local
171→                ReaderTagList localTopics = new ReaderTagList();
172→                localTopics.addAll(ReaderTagTable.getDefaultTags());
173→                localTopics.addAll(ReaderTagTable.getFollowedTags());
174→                localTopics.addAll(ReaderTagTable.getBookmarkTags());
175→                localTopics.addAll(ReaderTagTable.getCustomListTags());
176→
177→                if (
178→                        !localTopics.isSameList(serverTopics)
179→                        || displayNameUpdateWasNeeded
180→                ) {
181→                    AppLog.d(AppLog.T.READER, "reader service > followed topics changed "
182→                                              + "updatedDisplayNames [" + displayNameUpdateWasNeeded + "]");
183→
184→                    if (!mAccountStore.hasAccessToken()) {
185→                        // Do not delete locally saved tags for logged out user
186→                        ReaderTagTable.addOrUpdateTags(serverTopics);
187→                    } else {
188→                        // if any local topics have been removed from the server, make sure to delete
189→                        // them locally
190→                        ReaderTagTable.deleteTags(localTopics.getDeletions(serverTopics));
191→                        // now replace local topics with the server topics
192→                        ReaderTagTable.replaceTags(serverTopics);
193→                    }
194→                    // broadcast the fact that there are changes
195→                    EventBus.getDefault().post(new ReaderEvents.FollowedTagsChanged(true));
196→                }
197→                AppPrefs.setReaderTagsUpdatedTimestamp(new Date().getTime());
198→
199→                taskCompleted(UpdateTask.TAGS);
200→            }
201→        }.start();
202→    }
