204→    /*
205→     * parse a specific topic section from the topic response
206→     */
207→    private static ReaderTagList parseTags(JSONObject jsonObject, String name, ReaderTagType tagType) {
208→        ReaderTagList topics = new ReaderTagList();
209→
210→        if (jsonObject == null) {
211→            return topics;
212→        }
213→
214→        JSONObject jsonTopics = jsonObject.optJSONObject(name);
215→        if (jsonTopics == null) {
216→            return topics;
217→        }
218→
219→        Iterator<String> it = jsonTopics.keys();
220→        while (it.hasNext()) {
221→            String internalName = it.next();
222→            JSONObject jsonTopic = jsonTopics.optJSONObject(internalName);
223→            if (jsonTopic != null) {
224→                String tagTitle = JSONUtils.getStringDecoded(jsonTopic, ReaderConstants.JSON_TAG_TITLE);
225→                String tagDisplayName = JSONUtils.getStringDecoded(jsonTopic, ReaderConstants.JSON_TAG_DISPLAY_NAME);
226→                String tagSlug = JSONUtils.getStringDecoded(jsonTopic, ReaderConstants.JSON_TAG_SLUG);
227→                String endpoint = JSONUtils.getString(jsonTopic, ReaderConstants.JSON_TAG_URL);
228→
229→                // if the endpoint contains `read/list` then this is a custom list - these are
230→                // included in the response as default tags
231→                if (tagType == ReaderTagType.DEFAULT && endpoint.contains("/read/list/")) {
232→                    topics.add(new ReaderTag(tagSlug, tagDisplayName, tagTitle, endpoint, ReaderTagType.CUSTOM_LIST));
233→                } else {
234→                    topics.add(new ReaderTag(tagSlug, tagDisplayName, tagTitle, endpoint, tagType));
235→                }
236→            }
237→        }
238→
239→        return topics;
240→    }
