242→    private static ReaderTagList parseInterestTags(JSONObject jsonObject) {
243→        ReaderTagList interestTags = new ReaderTagList();
244→
245→        if (jsonObject == null) {
246→            return interestTags;
247→        }
248→
249→        JSONArray jsonInterests = jsonObject.optJSONArray(INTERESTS);
250→
251→        if (jsonInterests == null) {
252→            return interestTags;
253→        }
254→
255→        for (int i = 0; i < jsonInterests.length(); i++) {
256→            JSONObject jsonInterest = jsonInterests.optJSONObject(i);
257→            if (jsonInterest != null) {
258→                String tagTitle = JSONUtils.getStringDecoded(jsonInterest, ReaderConstants.JSON_TAG_TITLE);
259→                String tagSlug = JSONUtils.getStringDecoded(jsonInterest, ReaderConstants.JSON_TAG_SLUG);
260→                interestTags.add(new ReaderTag(tagSlug, tagTitle, tagTitle, "", ReaderTagType.INTERESTS));
261→            }
262→        }
263→
264→        return interestTags;
265→    }
