1004→    private void updatePosts(boolean forced) {
1005→        if (!isAdded()) {
1006→            return;
1007→        }
1008→
1009→        if (!NetworkUtils.checkConnection(getActivity())) {
1010→            mRecyclerView.setRefreshing(false);
1011→            return;
1012→        }
1013→
1014→        if (forced) {
1015→            // Update the tags on post refresh since following some sites (like P2) will change followed tags and blogs
1016→            ReaderUpdateServiceStarter.startService(getContext(),
1017→                    EnumSet.of(UpdateTask.TAGS));
1018→        }
1019→
1020→        if (mFirstLoad) {
1021→            // let onResume() take care of this logic, as the FilteredRecyclerView.FilterListener onLoadData
1022→            // method is called on two moments: once for first time load, and then each time the swipe to
1023→            // refresh gesture triggers a refresh.
1024→            mRecyclerView.setRefreshing(false);
1025→            mFirstLoad = false;
1026→        } else {
1027→            UpdateAction updateAction = forced ? UpdateAction.REQUEST_REFRESH
1028→                    : UpdateAction.REQUEST_NEWER;
1029→            switch (getPostListType()) {
1030→                case TAG_FOLLOWED:
1031→                    // fall through to TAG_PREVIEW
1032→                case TAG_PREVIEW:
1033→                    updatePostsWithTag(getCurrentTag(), updateAction);
1034→                    break;
1035→                case BLOG_PREVIEW:
1036→                    updatePostsInCurrentBlogOrFeed(updateAction);
1037→                    break;
1038→                case SEARCH_RESULTS:
1039→                    // no-op
1040→                    break;
1041→            }
1042→            // make sure swipe-to-refresh progress shows since this is a manual refresh
1043→            mRecyclerView.setRefreshing(true);
1044→        }
1045→        if (getCurrentTag() != null && getCurrentTag().isBookmarked()) {
1046→            ReaderPostTable.purgeUnbookmarkedPostsWithBookmarkTag();
1047→            refreshPosts();
1048→        }
